good-example.code-block:
public ReleaseDecision evaluateDigitalOmnibusAssumption(ReleaseEvidence evidence) {
    List<String> blockers = new ArrayList<>();

    requirePresent(evidence.digitalOmnibusSourceStatus(), "Digital Omnibus source-status record", blockers);
    requirePresent(evidence.affectedRegulationMap(), "affected-regulation mapping", blockers);
    requireApproved(evidence.legalStatusDecision(), "qualified legal/compliance status decision", blockers);
    requireApproved(evidence.controlRelaxationDecision(), "approved decision before any control relaxation", blockers);
    requirePassing(evidence.regulationSkillCompatibilityCheck(), "compatibility with 801-804 regulation-skill outputs", blockers);

    if (!blockers.isEmpty()) {
        return ReleaseDecision.blocked(
            evidence.serviceId(),
            blockers,
            Escalation.required("legal", "compliance", "privacy", "security", "risk", "ai-governance")
        );
    }

    return ReleaseDecision.approvedWithEvidence(evidence.serviceId(), evidence.references(), evidence.approvers());
}

bad-example.code-block:
public ReleaseDecision evaluateDigitalOmnibusAssumption(ReleaseEvidence evidence) {
    return ReleaseDecision.approved(evidence.serviceId(), "Digital Omnibus will simplify this soon");
}

good-example.code-block:
public WorkflowImpact assessWorkflowImpact(IncidentAndRightsWorkflow workflow) {
    return WorkflowImpact.builder()
        .sourceStatusRequired(true)
        .candidate("Evaluate single-entry incident reporting intake")
        .preserveExistingControl("NIS2 severity triage")
        .preserveExistingControl("DORA financial ICT incident handoff")
        .preserveExistingControl("GDPR personal-data breach assessment")
        .preserveExistingControl("data-subject rights request deadlines and evidence")
        .requiredOwners(List.of("security-operations", "privacy-owner", "resilience-owner", "legal-compliance"))
        .decision("consolidation-candidate-only-until-approved")
        .build();
}

